const people = JSON.parse(fs.readFileSync(FILE, 'utf-8'));

let updated = 0;
for (const seed of SEEDS) {
  const person = people.find(p => p.id === seed.personId);
  if (!person) { console.log(`! person not found: ${seed.personId}`); continue; }
  const ev = (person.events || []).find(e => e.year === seed.year);
  if (!ev) { console.log(`! event ${seed.personId} ${seed.year} not found`); continue; }
  ev.sections = seed.sections;
  updated++;
  console.log(`✓ ${person.name} ${seed.year} ← ${seed.sections.length} sections`);
}

fs.writeFileSync(FILE, JSON.stringify(people, null, 2) + '\n', 'utf-8');
console.log(`\nГотово: ${updated} событий обновлено.`);
